    """
    A class that checks if a value is a valid hash of a given algorithm/hash-type.
    """

    hash_length_map = {
        'md5': 32,
        'sha1': 40,
        'sha224': 56,
        'sha256': 64,
        'sha384': 96,
        'sha512': 128,
    }

    def __init__(self, algorithm: Literal['md5', 'sha1', 'sha224', 'sha256', 'sha384', 'sha512']):
        """
        Args:
            algorithm: The algorithm to use for the hash, must be one of `'md5'`, `'sha1'`, `'sha224'`, `'sha256'`,
                `'sha384'`, or `'sha512'`.

        ```py title="IsHash"
        import hashlib
        from dirty_equals import IsHash

        assert hashlib.md5(b'hello').hexdigest() == IsHash('md5')
        assert hashlib.sha256(b'hello').hexdigest() == IsHash('sha256')
        assert 'not_a_hash' != IsHash('md5')
        ```
        """
        self.algorithm = algorithm
        try:
            self.length = self.hash_length_map[algorithm.lower()]
        except KeyError:
            raise ValueError(f'Unknown hash algorithm: {algorithm!r}')
        super().__init__(plain_repr(repr(algorithm)))

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False
        if len(other) != self.length:
            return False
        return bool(re.fullmatch('[0-9a-fA-F]+', other))

